'use client';

import React, { useState, useEffect, useRef } from 'react';
import { useOS, OSTheme } from '../../context/OSContext';
import { Wallpaper } from './Wallpaper';
import { TopBar } from './TopBar';
import { Dock } from './Dock';
import { Window } from './Window';

// Import apps
import { PortfolioApp } from '../Apps/PortfolioApp';
import { AIDashboardApp } from '../Apps/AIDashboardApp';
import { MarketingDeskApp } from '../Apps/MarketingDeskApp';
import { WorkspaceApp } from '../Apps/WorkspaceApp';
import { AdminApp } from '../Apps/AdminApp';

import { 
  User, 
  Cpu, 
  BarChart3, 
  FolderOpen, 
  Settings, 
  Search, 
  Sparkles,
  Link,
  ChevronRight,
  MonitorPlay
} from 'lucide-react';

export const Desktop: React.FC = () => {
  const { 
    windows, 
    openWindow, 
    setTheme, 
    setWallpaper,
    setMusicPlaying,
    portfolioData,
    notes,
    bookmarks
  } = useOS();

  const [commandPaletteOpen, setCommandPaletteOpen] = useState(false);
  const [commandSearch, setCommandSearch] = useState('');
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Keyboard shortcut listener (Ctrl+K or Cmd+K to open Command Palette)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        setCommandPaletteOpen(prev => !prev);
      }
      if (e.key === 'Escape') {
        setCommandPaletteOpen(false);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  useEffect(() => {
    if (commandPaletteOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    } else {
      setCommandSearch('');
    }
  }, [commandPaletteOpen]);

  // Desktop shortcuts configurations
  const desktopShortcuts = [
    { id: 'portfolio', title: 'Portfolio Website', icon: User, color: 'text-blue-400' },
    { id: 'ai_dashboard', title: 'AI Command Center', icon: Cpu, color: 'text-purple-400' },
    { id: 'marketing_desk', title: 'Marketing KPI Desk', icon: BarChart3, color: 'text-emerald-400' },
    { id: 'workspace', title: 'Workspace Tools', icon: FolderOpen, color: 'text-orange-400' },
    { id: 'admin', title: 'CMS Settings', icon: Settings, color: 'text-amber-400' }
  ];

  // Command palette search results compiler
  const getCommandResults = () => {
    const query = commandSearch.toLowerCase().trim();
    const results: Array<{ title: string; category: string; action: () => void }> = [];

    if (!query) {
      // Default recommended actions
      return [
        { title: 'Open Portfolio Website', category: 'Application', action: () => openWindow('portfolio') },
        { title: 'Open AI Command Center', category: 'Application', action: () => openWindow('ai_dashboard') },
        { title: 'Switch to Gotham Batman Theme', category: 'Aesthetic Settings', action: () => setTheme('batman') },
        { title: 'Switch to Cyberpunk 2077 Theme', category: 'Aesthetic Settings', action: () => setTheme('cyberpunk') },
        { title: 'Start Ambient Background Music', category: 'Audio Player', action: () => setMusicPlaying(true) }
      ];
    }

    // 1. Search Apps
    desktopShortcuts.forEach(app => {
      if (app.title.toLowerCase().includes(query)) {
        results.push({
          title: `Launch ${app.title}`,
          category: 'Apps Launcher',
          action: () => openWindow(app.id)
        });
      }
    });

    // 2. Search CMS Projects
    portfolioData.projects.forEach(p => {
      if (p.title.toLowerCase().includes(query) || p.category.toLowerCase().includes(query) || p.longDescription.toLowerCase().includes(query)) {
        results.push({
          title: `Project Case Study: ${p.title} (ROAS: ${p.metrics.roas || 'N/A'})`,
          category: 'Portfolio Project',
          action: () => { openWindow('portfolio'); }
        });
      }
    });

    // 3. Search Workspace Notes
    notes.forEach(note => {
      if (note.title.toLowerCase().includes(query) || note.content.toLowerCase().includes(query)) {
        results.push({
          title: `Workspace Note: ${note.title}`,
          category: 'Notes App',
          action: () => openWindow('workspace')
        });
      }
    });

    // 4. Search Bookmarks
    bookmarks.forEach(bmk => {
      if (bmk.name.toLowerCase().includes(query) || bmk.url.toLowerCase().includes(query)) {
        results.push({
          title: `Bookmark Link: ${bmk.name}`,
          category: 'Bookmarks App',
          action: () => window.open(bmk.url, '_blank')
        });
      }
    });

    // 5. Themes togglers
    const themes: OSTheme[] = ['glass', 'apple', 'batman', 'cyberpunk', 'neon', 'matrix', 'dark', 'luxury'];
    themes.forEach(t => {
      if (t.includes(query) || `${t} theme`.includes(query)) {
        results.push({
          title: `Switch Theme to: ${t}`,
          category: 'Aesthetics',
          action: () => setTheme(t)
        });
      }
    });

    return results;
  };

  return (
    <div className="relative flex-1 w-full h-full overflow-hidden flex flex-col justify-between">
      {/* Live wallpaper backgrounds */}
      <Wallpaper />

      {/* Header Panel */}
      <TopBar />

      {/* Main Desktop Grid Workspace Area */}
      <div className="flex-1 w-full h-full p-6 relative flex flex-col items-start gap-4 content-start overflow-hidden">
        
        {/* Desktop grid shortcuts */}
        <div className="flex flex-col gap-6 select-none z-10">
          {desktopShortcuts.map((shortcut) => {
            const Icon = shortcut.icon;
            return (
              <div 
                key={shortcut.id}
                onDoubleClick={() => openWindow(shortcut.id)}
                onClick={() => openWindow(shortcut.id)}
                className="w-20 flex flex-col items-center gap-1.5 cursor-pointer p-1 rounded-xl hover:bg-white/10 group transition-all text-center"
              >
                <div className={`w-12 h-12 rounded-xl bg-white/5 border border-white/5 group-hover:border-white/15 flex items-center justify-center shadow-lg transition-transform transform group-hover:scale-105 active:scale-95`}>
                  <Icon className={`w-6 h-6 ${shortcut.color} glowing-text`} />
                </div>
                <span className="text-[10px] font-bold text-white tracking-wide text-shadow-sm select-none break-words leading-tight px-0.5">
                  {shortcut.title}
                </span>
              </div>
            );
          })}

          {/* Search Shortcut */}
          <div 
            onClick={() => setCommandPaletteOpen(true)}
            className="w-20 flex flex-col items-center gap-1.5 cursor-pointer p-1 rounded-xl hover:bg-white/10 group transition-all text-center"
          >
            <div className="w-12 h-12 rounded-xl bg-white/5 border border-white/5 group-hover:border-white/15 flex items-center justify-center shadow-lg transition-transform transform group-hover:scale-105 active:scale-95">
              <Sparkles className="w-6 h-6 text-cyan-400 glowing-text" />
            </div>
            <span className="text-[10px] font-bold text-white tracking-wide text-shadow-sm select-none leading-tight">
              Command Palette (Ctrl+K)
            </span>
          </div>
        </div>
        {/* Standalone Native Window Popups active; Virtual DOM windows removed */}
      </div>

      {/* Dock bottom launchers panel */}
      <Dock />

      {/* Command Palette Search Overlay */}
      {commandPaletteOpen && (
        <>
          <div 
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 transition-all select-none"
            onClick={() => setCommandPaletteOpen(false)}
          />
          <div className="fixed top-1/4 left-1/2 -translate-x-1/2 w-full max-w-xl glass-panel-heavy rounded-2xl shadow-2xl border border-cyan-500/25 overflow-hidden z-50 text-white flex flex-col">
            
            {/* Search Input Bar */}
            <div className="p-4 flex items-center gap-3 border-b border-white/5">
              <Search className="w-5 h-5 text-cyan-400 shrink-0" />
              <input 
                ref={searchInputRef}
                type="text"
                value={commandSearch}
                onChange={(e) => setCommandSearch(e.target.value)}
                placeholder="Search projects, documents, open apps, change themes (Ctrl+K)..."
                className="w-full bg-transparent text-sm text-white placeholder-white/40 outline-none"
              />
              <button 
                onClick={() => setCommandPaletteOpen(false)}
                className="text-[10px] uppercase font-bold bg-white/10 hover:bg-white/15 px-2 py-1 rounded text-slate-300"
              >
                ESC
              </button>
            </div>

            {/* Results items */}
            <div className="max-h-72 overflow-y-auto p-2 flex flex-col gap-0.5">
              {getCommandResults().length > 0 ? (
                getCommandResults().map((res, i) => (
                  <button
                    key={i}
                    onClick={() => { res.action(); setCommandPaletteOpen(false); }}
                    className="w-full text-left p-2.5 rounded-xl hover:bg-cyan-500/10 hover:text-white text-slate-200 transition-colors flex items-center justify-between text-xs group"
                  >
                    <span className="font-semibold flex items-center gap-2">
                      <ChevronRight className="w-3.5 h-3.5 text-cyan-400 group-hover:translate-x-0.5 transition-transform" />
                      {res.title}
                    </span>
                    <span className="text-[9px] bg-white/5 border border-white/5 px-2 py-0.5 rounded text-white/50 group-hover:text-cyan-400 uppercase tracking-wider font-bold">
                      {res.category}
                    </span>
                  </button>
                ))
              ) : (
                <div className="py-8 text-center text-slate-500 text-xs">
                  No matching files, bookmarks, or system commands found.
                </div>
              )}
            </div>
          </div>
        </>
      )}

    </div>
  );
};
